def read_temperature_c():
    # Example sensor input: analog on GPIO34 (adjust to your sensor)
    # This is a placeholder conversion; replace with your sensor's formula.
    adc = ADC(Pin(34))
    adc.atten(ADC.ATTN_11DB)
    adc.width(ADC.WIDTH_12BIT)
    raw = adc.read()
    v = raw * 3.3 / 4095.0
    temp_c = (v - 0.5) * 100.0
    return temp_c


